(function () {
  function qs(selector, root) {
    return (root || document).querySelector(selector);
  }

  function qsa(selector, root) {
    return Array.prototype.slice.call((root || document).querySelectorAll(selector));
  }

  function filterClinics() {
    var input = qs('[data-search]');
    if (!input) return;
    var cards = qsa('[data-clinic]');
    input.addEventListener('input', function () {
      var query = input.value.trim().toLowerCase();
      cards.forEach(function (card) {
        var haystack = card.getAttribute('data-clinic').toLowerCase();
        card.style.display = haystack.indexOf(query) >= 0 ? 'grid' : 'none';
      });
    });
  }

  function chips() {
    qsa('[data-chip]').forEach(function (chip) {
      chip.addEventListener('click', function () {
        qsa('[data-chip]').forEach(function (item) { item.classList.remove('is-active'); });
        chip.classList.add('is-active');
      });
    });
  }

  function queueSheet() {
    var sheet = qs('[data-sheet]');
    var openers = qsa('[data-open-sheet]');
    var closers = qsa('[data-close-sheet]');
    if (!sheet || !openers.length) return;
    openers.forEach(function (button) {
      button.addEventListener('click', function () {
        sheet.classList.add('is-open');
        sheet.setAttribute('aria-hidden', 'false');
      });
    });
    closers.forEach(function (button) {
      button.addEventListener('click', function () {
        sheet.classList.remove('is-open');
        sheet.setAttribute('aria-hidden', 'true');
      });
    });
  }

  function ticketActions() {
    var checkin = qs('[data-checkin]');
    var state = qs('[data-checkin-state]');
    var leave = qs('[data-leave]');
    if (checkin && state) {
      checkin.addEventListener('click', function () {
        state.classList.add('is-visible');
        checkin.textContent = 'Checked in';
        checkin.setAttribute('disabled', 'disabled');
      });
    }
    if (leave) {
      leave.addEventListener('click', function () {
        leave.textContent = 'Queue left';
        leave.setAttribute('disabled', 'disabled');
      });
    }
  }

  document.addEventListener('DOMContentLoaded', function () {
    filterClinics();
    chips();
    queueSheet();
    ticketActions();
  });
})();

